(window.webpackJsonp=window.webpackJsonp||[]).push([[902],{856:function(s){s.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number[]}</span> <span class=\\"hljs-variable\\">heights</span></span>\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number}</span> <span class=\\"hljs-variable\\">bricks</span></span>\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number}</span> <span class=\\"hljs-variable\\">ladders</span></span>\\n * <span class=\\"hljs-doctag\\">@return <span class=\\"hljs-type\\">{number}</span></span>\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> furthestBuilding = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">heights, bricks, ladders</span>) </span>{\\n    <span class=\\"hljs-keyword\\">let</span> ladderUse=[]\\n    <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span> <span class=\\"hljs-title\\">insert</span>(<span class=\\"hljs-params\\">num</span>)</span>{\\n        <span class=\\"hljs-keyword\\">if</span>(ladderUse.length===<span class=\\"hljs-number\\">0</span> || ladderUse[ladderUse.length<span class=\\"hljs-number\\">-1</span>]&lt;=num){\\n            ladderUse.push(num)\\n        }<span class=\\"hljs-keyword\\">else</span>{\\n            <span class=\\"hljs-keyword\\">let</span> idx=bsEnd(ladderUse,num)\\n            ladderUse.splice(idx,<span class=\\"hljs-number\\">0</span>,num)\\n        }\\n    }\\n    <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span> <span class=\\"hljs-title\\">bsEnd</span>(<span class=\\"hljs-params\\">arr,n</span>)</span>{\\n        <span class=\\"hljs-keyword\\">let</span> lo=<span class=\\"hljs-number\\">0</span>,hi=arr.length<span class=\\"hljs-number\\">-1</span>\\n        <span class=\\"hljs-keyword\\">while</span>(lo&lt;hi){\\n            <span class=\\"hljs-keyword\\">let</span> mid=<span class=\\"hljs-built_in\\">Math</span>.floor((lo+hi)/<span class=\\"hljs-number\\">2</span>)\\n            <span class=\\"hljs-keyword\\">if</span>(arr[mid]&lt;n)lo=mid+<span class=\\"hljs-number\\">1</span>\\n            <span class=\\"hljs-keyword\\">else</span> hi=mid\\n        }\\n        <span class=\\"hljs-keyword\\">return</span> hi\\n    }\\n\\n\\n    <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">1</span>;i&lt;heights.length;i++){\\n        <span class=\\"hljs-keyword\\">let</span> lastH=heights[i<span class=\\"hljs-number\\">-1</span>]\\n        <span class=\\"hljs-keyword\\">let</span> curH=heights[i]\\n        <span class=\\"hljs-keyword\\">let</span> gap=curH-lastH\\n        <span class=\\"hljs-keyword\\">if</span>(gap&gt;<span class=\\"hljs-number\\">0</span>){\\n            <span class=\\"hljs-keyword\\">if</span>(ladders&gt;<span class=\\"hljs-number\\">0</span>){\\n                ladders--\\n                insert(gap)\\n                <span class=\\"hljs-keyword\\">continue</span>\\n            }<span class=\\"hljs-keyword\\">else</span>{\\n                <span class=\\"hljs-keyword\\">let</span> minGap=ladderUse[<span class=\\"hljs-number\\">0</span>]\\n                <span class=\\"hljs-keyword\\">if</span>(minGap&lt;gap){\\n                    ladderUse.shift()\\n                    insert(gap)\\n                }<span class=\\"hljs-keyword\\">else</span>{\\n                    minGap=gap\\n                }\\n                bricks -= minGap\\n                <span class=\\"hljs-keyword\\">if</span>(bricks&lt;<span class=\\"hljs-number\\">0</span>){\\n                    <span class=\\"hljs-keyword\\">return</span> i<span class=\\"hljs-number\\">-1</span>\\n                }\\n            }\\n        }\\n    }\\n    <span class=\\"hljs-keyword\\">return</span> heights.length<span class=\\"hljs-number\\">-1</span>\\n};\\n</code></pre>\\n"],"titleSlug":"furthest-building-you-can-reach","hasThinking":false,"content":"<p>\u7ed9\u4f60\u4e00\u4e2a\u6574\u6570\u6570\u7ec4 <code>heights</code> \uff0c\u8868\u793a\u5efa\u7b51\u7269\u7684\u9ad8\u5ea6\u3002\u53e6\u6709\u4e00\u4e9b\u7816\u5757 <code>bricks</code> \u548c\u68af\u5b50 <code>ladders</code> \u3002</p>\\n\\n<p>\u4f60\u4ece\u5efa\u7b51\u7269 <code>0</code> \u5f00\u59cb\u65c5\u7a0b\uff0c\u4e0d\u65ad\u5411\u540e\u9762\u7684\u5efa\u7b51\u7269\u79fb\u52a8\uff0c\u671f\u95f4\u53ef\u80fd\u4f1a\u7528\u5230\u7816\u5757\u6216\u68af\u5b50\u3002</p>\\n\\n<p>\u5f53\u4ece\u5efa\u7b51\u7269 <code>i</code> \u79fb\u52a8\u5230\u5efa\u7b51\u7269 <code>i+1</code>\uff08\u4e0b\u6807<strong> \u4ece 0 \u5f00\u59cb </strong>\uff09\u65f6\uff1a</p>\\n\\n<ul>\\n\\t<li>\u5982\u679c\u5f53\u524d\u5efa\u7b51\u7269\u7684\u9ad8\u5ea6 <strong>\u5927\u4e8e\u6216\u7b49\u4e8e</strong> \u4e0b\u4e00\u5efa\u7b51\u7269\u7684\u9ad8\u5ea6\uff0c\u5219\u4e0d\u9700\u8981\u68af\u5b50\u6216\u7816\u5757</li>\\n\\t<li>\u5982\u679c\u5f53\u524d\u5efa\u7b51\u7684\u9ad8\u5ea6 <strong>\u5c0f\u4e8e</strong> \u4e0b\u4e00\u4e2a\u5efa\u7b51\u7684\u9ad8\u5ea6\uff0c\u60a8\u53ef\u4ee5\u4f7f\u7528 <strong>\u4e00\u67b6\u68af\u5b50</strong> \u6216 <strong><code>(h[i+1] - h[i])</code> \u4e2a\u7816\u5757</strong></li>\\n</ul>\\n\u5982\u679c\u4ee5\u6700\u4f73\u65b9\u5f0f\u4f7f\u7528\u7ed9\u5b9a\u7684\u68af\u5b50\u548c\u7816\u5757\uff0c\u8fd4\u56de\u4f60\u53ef\u4ee5\u5230\u8fbe\u7684\u6700\u8fdc\u5efa\u7b51\u7269\u7684\u4e0b\u6807\uff08\u4e0b\u6807<strong> \u4ece 0 \u5f00\u59cb </strong>\uff09\u3002\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u793a\u4f8b 1\uff1a</strong></p>\\n<img alt=\\"\\" src=\\"https://assets.leetcode-cn.com/aliyun-lc-upload/uploads/2020/10/31/q4.gif\\" style=\\"width: 562px; height: 561px;\\" />\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>heights = [4,2,7,6,9,14,12], bricks = 5, ladders = 1\\n<strong>\u8f93\u51fa\uff1a</strong>4\\n<strong>\u89e3\u91ca\uff1a</strong>\u4ece\u5efa\u7b51\u7269 0 \u51fa\u53d1\uff0c\u4f60\u53ef\u4ee5\u6309\u6b64\u65b9\u6848\u5b8c\u6210\u65c5\u7a0b\uff1a\\n- \u4e0d\u4f7f\u7528\u7816\u5757\u6216\u68af\u5b50\u5230\u8fbe\u5efa\u7b51\u7269 1 \uff0c\u56e0\u4e3a 4 >= 2\\n- \u4f7f\u7528 5 \u4e2a\u7816\u5757\u5230\u8fbe\u5efa\u7b51\u7269 2 \u3002\u4f60\u5fc5\u987b\u4f7f\u7528\u7816\u5757\u6216\u68af\u5b50\uff0c\u56e0\u4e3a 2 < 7\\n- \u4e0d\u4f7f\u7528\u7816\u5757\u6216\u68af\u5b50\u5230\u8fbe\u5efa\u7b51\u7269 3 \uff0c\u56e0\u4e3a 7 >= 6\\n- \u4f7f\u7528\u552f\u4e00\u7684\u68af\u5b50\u5230\u8fbe\u5efa\u7b51\u7269 4 \u3002\u4f60\u5fc5\u987b\u4f7f\u7528\u7816\u5757\u6216\u68af\u5b50\uff0c\u56e0\u4e3a 6 < 9\\n\u65e0\u6cd5\u8d8a\u8fc7\u5efa\u7b51\u7269 4 \uff0c\u56e0\u4e3a\u6ca1\u6709\u66f4\u591a\u7816\u5757\u6216\u68af\u5b50\u3002\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 2\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>heights = [4,12,2,7,3,18,20,3,19], bricks = 10, ladders = 2\\n<strong>\u8f93\u51fa\uff1a</strong>7\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 3\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>heights = [14,3,19,3], bricks = 17, ladders = 0\\n<strong>\u8f93\u51fa\uff1a</strong>3\\n</pre>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li><code>1 <= heights.length <= 10<sup>5</sup></code></li>\\n\\t<li><code>1 <= heights[i] <= 10<sup>6</sup></code></li>\\n\\t<li><code>0 <= bricks <= 10<sup>9</sup></code></li>\\n\\t<li><code>0 <= ladders <= heights.length</code></li>\\n</ul>\\n","title":"1642. \u53ef\u4ee5\u5230\u8fbe\u7684\u6700\u8fdc\u5efa\u7b51","relatedTags":["\u5806","\u4e8c\u5206\u67e5\u627e"],"difficult":"Middle","lang":["javascript"],"uniqueID":"1642"}')}}]);